function check_tokenRolesInit_cannotReinitialize(address owner1, address operator1, address owner2, address operator2) public {
    // First initialization succeeds
    tokenRoles.__TokenRoles_init(owner1, operator1);

    // Store the owner after first init
    address ownerAfterFirstInit = tokenRoles.owner();

    // Attempt second initialization - should revert
    try tokenRoles.__TokenRoles_init(owner2, operator2) {
        // If we reach here, re-initialization succeeded (BUG)
        assert(false);
    } catch {
        // Expected behavior - should revert
        assert(tokenRoles.owner() == ownerAfterFirstInit);
    }
}
